**Approach — Floyd-Warshall**: For each intermediate `k`, for each pair `(i,j)`, try going `i -> k -> j`.

```javascript
function allPairsShortest(n, edges) {
  const INF = Infinity;
  const dist = Array.from({length: n}, () => new Array(n).fill(INF));
  for (let i = 0; i < n; i++) dist[i][i] = 0;
  for (const [u, v, w] of edges) {
    if (w < dist[u][v]) dist[u][v] = w;
  }
  for (let k = 0; k < n; k++) {
    for (let i = 0; i < n; i++) {
      for (let j = 0; j < n; j++) {
        if (dist[i][k] + dist[k][j] < dist[i][j]) {
          dist[i][j] = dist[i][k] + dist[k][j];
        }
      }
    }
  }
  const result = [];
  for (let i = 0; i < n; i++) {
    const row = [];
    for (let j = 0; j < n; j++) row.push(dist[i][j] === INF ? -1 : dist[i][j]);
    result.push(row);
  }
  return result;
}
```

