  constructor() { this.h = []; }
  size() { return this.h.length; }
  push(x) { this.h.push(x); let i=this.h.length-1; while (i>0) { const p=(i-1)>>1; if (this.h[p][0]<=this.h[i][0]) break; [this.h[p],this.h[i]]=[this.h[i],this.h[p]]; i=p; } }
