  if (n === 1) return 0;
  const adj = Array.from({length: n}, () => []);
  for (const [u, v, w] of edges) { adj[u].push([v, w]); adj[v].push([u, w]); }
  const visited = new Array(n).fill(false);
  const heap = new MinHeap();
  heap.push([0, 0]);
  let total = 0, count = 0;
  while (heap.size() && count < n) {
    const [w, u] = heap.pop();
    if (visited[u]) continue;
    visited[u] = true;
    total += w;
    count++;
