**Approach — Kruskal + Union-Find**: Sort edges by weight; greedily add an edge iff its endpoints are in different components.

```javascript
class UnionFind {
  constructor(n) { this.p = Array.from({length: n}, (_, i) => i); this.r = new Array(n).fill(0); }
  find(x) { while (this.p[x] !== x) { this.p[x] = this.p[this.p[x]]; x = this.p[x]; } return x; }
  union(a, b) {
    const ra = this.find(a), rb = this.find(b);
    if (ra === rb) return false;
    if (this.r[ra] < this.r[rb]) this.p[ra] = rb;
    else if (this.r[ra] > this.r[rb]) this.p[rb] = ra;
    else { this.p[rb] = ra; this.r[ra]++; }
    return true;
  }
}

function mstKruskal(n, edges) {
  const sorted = edges.slice().sort((a, b) => a[2] - b[2]);
  const uf = new UnionFind(n);
  let total = 0, accepted = 0;
  for (const [u, v, w] of sorted) {
    if (uf.union(u, v)) { total += w; accepted++; }
    if (accepted === n - 1) break;
  }
  return accepted === n - 1 ? total : (n === 1 ? 0 : -1);
}
```

**Time**: O(E log E).

