  for (const [u, v] of tickets) {
    if (!adj.has(u)) adj.set(u, []);
    adj.get(u).push(v);
  }
  for (const list of adj.values()) list.sort();
  const path = [];
  function dfs(u) {
    const list = adj.get(u);
    while (list && list.length) {
