function alienOrder(words) {
  const letters = new Set();
  for (const w of words) for (const c of w) letters.add(c);
  const adj = new Map();
  const indeg = new Map();
  for (const c of letters) { adj.set(c, new Set()); indeg.set(c, 0); }
  for (let i = 0; i + 1 < words.length; i++) {
    const a = words[i], b = words[i+1];
    let found = false;
    const len = Math.min(a.length, b.length);
    for (let j = 0; j < len; j++) {
      if (a[j] !== b[j]) {
        if (!adj.get(a[j]).has(b[j])) {
          adj.get(a[j]).add(b[j]);
          indeg.set(b[j], indeg.get(b[j]) + 1);
        }
        found = true;
        break;
      }
    }
    if (!found && a.length > b.length) return '';
  }
  const heap = new MinHeap();
  for (const [c, d] of indeg) if (d === 0) heap.push(c);
  let result = '';
  while (heap.size()) {
    const c = heap.pop();
    result += c;
    for (const nb of adj.get(c)) {
      indeg.set(nb, indeg.get(nb) - 1);
      if (indeg.get(nb) === 0) heap.push(nb);
    }
  }
  return result.length === letters.size ? result : '';
}
