**Approach — Kosaraju's two-pass DFS**:
1. DFS on original graph, push nodes to a stack on finish.
2. Build reverse graph. Pop from stack; if unvisited, DFS in reverse graph — that DFS visits exactly one SCC.

```javascript
function countSCCs(n, edges) {
  const adj = Array.from({length: n}, () => []);
  const radj = Array.from({length: n}, () => []);
  for (const [u, v] of edges) { adj[u].push(v); radj[v].push(u); }
  const visited = new Array(n).fill(false);
  const stack = [];
  function dfs1(u) {
    visited[u] = true;
    for (const v of adj[u]) if (!visited[v]) dfs1(v);
    stack.push(u);
  }
  for (let i = 0; i < n; i++) if (!visited[i]) dfs1(i);
  visited.fill(false);
  function dfs2(u) {
    visited[u] = true;
    for (const v of radj[u]) if (!visited[v]) dfs2(v);
  }
  let count = 0;
  while (stack.length) {
    const u = stack.pop();
    if (!visited[u]) { dfs2(u); count++; }
  }
  return count;
}
```

**Time**: O(V+E).

