  constructor(n) { this.p = Array.from({length: n}, (_, i) => i); }
  find(x) { while (this.p[x] !== x) { this.p[x] = this.p[this.p[x]]; x = this.p[x]; } return x; }
  union(a, b) { const ra = this.find(a), rb = this.find(b); if (ra === rb) return false; this.p[ra] = rb; return true; }
}

function mstCost(n, edgeList, skipIdx) {
  const sorted = edgeList.map((e, i) => [...e, i]).sort((a, b) => a[2] - b[2]);
  const uf = new UnionFind(n);
  let total = 0, accepted = 0;
  for (const [u, v, w, idx] of sorted) {
    if (idx === skipIdx) continue;
    if (uf.union(u, v)) { total += w; accepted++; }
  }
  if (n > 0 && accepted < n - 1) return Infinity;
  return total;
}

function criticalMSTEdges(n, edges) {
  const baseline = mstCost(n, edges, -1);
  const result = [];
  for (let i = 0; i < edges.length; i++) {
    const without = mstCost(n, edges, i);
    if (without > baseline) result.push(i);
  }
  return result;
}
