      const nd = Math.max(d, Math.abs(heights[nr][nc] - heights[r][c]));
      if (nd < dist[nr][nc]) { dist[nr][nc] = nd; heap.push([nd, nr, nc]); }
    }
  }
  return 0;
}
```

**Time**: O(rows*cols*log(rows*cols)).

