**Approach — BFS 2-coloring**: Iterate every component. Start with color 0; for each unvisited node, BFS, alternating colors. A neighbor already colored the same color → not bipartite.

```javascript
function isBipartite(n, dislikes) {
  const adj = Array.from({length: n}, () => []);
  for (const [u, v] of dislikes) { adj[u].push(v); adj[v].push(u); }
  const color = new Array(n).fill(-1);
  for (let i = 0; i < n; i++) {
    if (color[i] !== -1) continue;
    color[i] = 0;
    const q = [i];
    while (q.length) {
      const u = q.shift();
      for (const v of adj[u]) {
        if (color[v] === -1) { color[v] = 1 - color[u]; q.push(v); }
        else if (color[v] === color[u]) return false;
      }
    }
  }
  return true;
}
```

**Time**: O(V+E).
